import json
import logging
import subprocess
import shlex
import re
import os
import pika

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Allowlist of permitted commands and their allowed argument patterns
ALLOWED_COMMANDS = {
    "python": {
        "allowed_args_pattern": r"^[\w\-./]+\.py$",  # Only .py files with safe characters
        "max_args": 5,
    },
    "echo": {
        "allowed_args_pattern": r"^[\w\s\-.,]+$",
        "max_args": 3,
    },
    "ls": {
        "allowed_args_pattern": r"^[\w\-./]+$",
        "max_args": 3,
    },
}

# Allowed base directories for file arguments
ALLOWED_DIRECTORIES = [
    "/opt/jobs/",
    "/var/data/processing/",
]

# Dangerous patterns that should never appear in arguments
DANGEROUS_PATTERNS = [
    ";", "&&", "||", "|", "`", "$(", "${", ">", "<", "\n", "\r",
    "..", "~", 
]


def validate_path(path: str) -> bool:
    """Validate that a file path is within allowed directories."""
    resolved = os.path.realpath(path)
    return any(resolved.startswith(allowed_dir) for allowed_dir in ALLOWED_DIRECTORIES)


def validate_argument(arg: str, pattern: str) -> bool:
    """Validate a single argument against the allowed pattern."""
    for dangerous in DANGEROUS_PATTERNS:
        if dangerous in arg:
            logger.warning(f"Dangerous pattern detected in argument: {arg}")
            return False
    return bool(re.match(pattern, arg))


def validate_command(command_dict: dict) -> list:
    """
    Validate and construct a safe command from a structured message.
    
    Expected message format:
    {
        "command": "python",
        "args": ["script.py", "--input", "data.csv"],
        "job_id": "12345"
    }
    
    Returns a list of command parts suitable for subprocess.run,
    or raises ValueError if validation fails.
    """
    if not isinstance(command_dict, dict):
        raise ValueError("Command must be a JSON object")

    command = command_dict.get("command", "")
    args = command_dict.get("args", [])
    job_id = command_dict.get("job_id", "unknown")

    if command not in ALLOWED_COMMANDS:
        raise ValueError(f"Command '{command}' is not in the allowlist. Job: {job_id}")

    config = ALLOWED_COMMANDS[command]

    if not isinstance(args, list):
        raise ValueError(f"Args must be a list. Job: {job_id}")

    if len(args) > config["max_args"]:
        raise ValueError(
            f"Too many arguments ({len(args)} > {config['max_args']}). Job: {job_id}"
        )

    validated_args = []
    for arg in args:
        if not isinstance(arg, str):
            raise ValueError(f"All arguments must be strings. Job: {job_id}")

        if not validate_argument(arg, config["allowed_args_pattern"]):
            raise ValueError(f"Invalid argument: '{arg}'. Job: {job_id}")

        # If argument looks like a path, validate it's in allowed directories
        if "/" in arg or arg.endswith(".py") or arg.endswith(".csv"):
            if not validate_path(arg):
                raise ValueError(
                    f"Path '{arg}' is not in allowed directories. Job: {job_id}"
                )

        validated_args.append(arg)

    return [command] + validated_args


def process_message(ch, method, properties, body):
    """Process a single message from the queue."""
    job_id = "unknown"
    try:
        message = json.loads(body)
        job_id = message.get("job_id", "unknown")
        logger.info(f"Processing job: {job_id}")

        # Validate and construct the command
        safe_command = validate_command(message)

        logger.info(f"Executing validated command for job {job_id}: {safe_command}")

        # Execute with security constraints
        result = subprocess.run(
            safe_command,
            shell=False,  # NEVER use shell=True with external input
            capture_output=True,
            text=True,
            timeout=300,  # 5 minute timeout
            cwd="/opt/jobs/",  # Restricted working directory
            env={  # Minimal environment
                "PATH": "/usr/bin:/usr/local/bin",
                "HOME": "/opt/jobs",
                "LANG": "C.UTF-8",
            },
        )

        if result.returncode == 0:
            logger.info(f"Job {job_id} completed successfully. Output: {result.stdout[:500]}")
        else:
            logger.error(
                f"Job {job_id} failed with return code {result.returncode}. "
                f"Stderr: {result.stderr[:500]}"
            )

        ch.basic_ack(delivery_tag=method.delivery_tag)

    except json.JSONDecodeError:
        logger.error(f"Invalid JSON in message body. Rejecting message.")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    except ValueError as e:
        logger.error(f"Command validation failed for job {job_id}: {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    except subprocess.TimeoutExpired:
        logger.error(f"Job {job_id} timed out after 300 seconds.")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    except Exception as e:
        logger.error(f"Unexpected error processing job {job_id}: {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)


def main():
    """Main entry point for the consumer."""
    rabbitmq_host = os.environ.get("RABBITMQ_HOST", "localhost")
    rabbitmq_port = int(os.environ.get("RABBITMQ_PORT", "5672"))
    rabbitmq_user = os.environ.get("RABBITMQ_USER", "guest")
    rabbitmq_pass = os.environ.get("RABBITMQ_PASS", "guest")
    queue_name = os.environ.get("QUEUE_NAME", "job_queue")

    credentials = pika.PlainCredentials(rabbitmq_user, rabbitmq_pass)
    connection_params = pika.ConnectionParameters(
        host=rabbitmq_host,
        port=rabbitmq_port,
        credentials=credentials,
        heartbeat=600,
    )

    connection = pika.BlockingConnection(connection_params)
    channel = connection.channel()

    channel.queue_declare(queue=queue_name, durable=True)
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue=queue_name, on_message_callback=process_message)

    logger.info(f"Consumer started. Waiting for messages on queue '{queue_name}'...")

    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        logger.info("Consumer shutting down...")
        channel.stop_consuming()
    finally:
        connection.close()


if __name__ == "__main__":
    main()